interface.definition:
#"SYSTEM_SYSRULES_headerContentLayout"(
  header: #"SYSTEM_SYSRULES_cardLayout"(
    contents: {
      #"SYSTEM_SYSRULES_headingField"(
        text: if(
          ri!isUpdate,
          "Update Attachment",
          "Create Attachment"
        ),
        size: "LARGE",
        fontWeight: "SEMI_BOLD"
      ),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        labelPosition: "COLLAPSED",
        value: {
          if(
            ri!isUpdate,
            "Update details for the attachment",
            "Enter details for the attachment"
          )
        }
      )
    },
    style: "ACCENT",
    padding: "STANDARD",
    showBorder: false
  ),
  isHeaderFixed: true,
  contents: {
    #"SYSTEM_SYSRULES_columnsLayout"(
      columns: {
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          contents: {
            #"SYSTEM_SYSRULES_sectionLayout_v1"(
              contents: {
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Title",
                      labelPosition: "ABOVE",
                      value: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/02925b99-1527-48bb-9fc8-406df81b2170"],
                      saveInto: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/02925b99-1527-48bb-9fc8-406df81b2170"],
                      characterLimit: 255,
                      showCharacterCount: false,
                      required: true
                    ),
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Type",
                      labelPosition: "ABOVE",
                      value: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/79c16d9b-9cce-4e0a-81bc-962f7bfc35e2"],
                      saveInto: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/79c16d9b-9cce-4e0a-81bc-962f7bfc35e2"],
                      characterLimit: 255,
                      showCharacterCount: false,
                      required: true,
                      marginAbove: "LESS"
                    ),
                    #"SYSTEM_SYSRULES_integerField"(
                      label: "Event Id",
                      labelPosition: "ABOVE",
                      value: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/354f153b-9e66-4694-a12f-7b254af55f30"],
                      saveInto: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/354f153b-9e66-4694-a12f-7b254af55f30"],
                      required: true,
                      marginAbove: "LESS"
                    )
                  },
                  style: "NONE",
                  shape: "SEMI_ROUNDED",
                  padding: "MORE"
                )
              },
              marginBelow: "MORE"
            ),
            #"SYSTEM_SYSRULES_ButtonLayout"(
              primaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: if(
                    ri!isUpdate,
                    "Save",
                    "Create"
                  ),
                  saveInto: {
                    if(
                      ri!isUpdate,
                      {
                        a!save(
                          target: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/95ad072d-de86-4bc1-bb11-74324a49a9a9"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/01c5a039-5e4d-439c-840a-791e0f3afd06"],
                          value: now()
                        )
                      },
                      {
                        a!save(
                          target: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/3ce6ad16-a3f7-4bed-adc0-bb2b85503448"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/592dad6a-0a5d-4275-9009-d5a3881729a0"],
                          value: now()
                        )
                      }
                    )
                  },
                  submit: true,
                  style: "SOLID",
                  validate: true
                )
              },
              secondaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: "Cancel",
                  value: true,
                  saveInto: ri!cancel,
                  submit: true,
                  style: "OUTLINE",
                  validate: false
                )
              }
            )
          },
          width: "WIDE"
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        )
      }
    )
  },
  backgroundColor: "#fbfbfb"
)
